class Solution:
    def countVisitedNodes(self, edges):
        n = len(edges)
        color = [0] * n
        ans = [0] * n
        for start in range(n):
            if color[start] != 0:
                continue
            path = []
            pos = {}
            node = start
            while color[node] == 0:
                color[node] = 1
                pos[node] = len(path)
                path.append(node)
                node = edges[node]
            if color[node] == 1:
                idx = pos[node]
                cyc_len = len(path) - idx
                for i in range(idx, len(path)):
                    ans[path[i]] = cyc_len
                    color[path[i]] = 2
                for i in range(idx - 1, -1, -1):
                    ans[path[i]] = ans[path[i + 1]] + 1
                    color[path[i]] = 2
            else:
                for i in range(len(path) - 1, -1, -1):
                    nxt = node if i == len(path) - 1 else path[i + 1]
                    ans[path[i]] = ans[nxt] + 1
                    color[path[i]] = 2
        return ans

