var countVisitedNodes = function(edges) {
    const n = edges.length;
    const color = new Array(n).fill(0);
    const ans = new Array(n).fill(0);
    for (let start = 0; start < n; start++) {
        if (color[start] !== 0) continue;
        const path = [];
        const pos = new Map();
        let node = start;
        while (color[node] === 0) {
            color[node] = 1;
            pos.set(node, path.length);
            path.push(node);
            node = edges[node];
        }
        if (color[node] === 1) {
            const idx = pos.get(node);
            const cycLen = path.length - idx;
            for (let i = idx; i < path.length; i++) {
                ans[path[i]] = cycLen;
                color[path[i]] = 2;
            }
            for (let i = idx - 1; i >= 0; i--) {
                ans[path[i]] = ans[path[i + 1]] + 1;
                color[path[i]] = 2;
            }
        } else {
            for (let i = path.length - 1; i >= 0; i--) {
                const nxt = (i === path.length - 1) ? node : path[i + 1];
                ans[path[i]] = ans[nxt] + 1;
                color[path[i]] = 2;
            }
        }
    }
    return ans;
};
